patch:
diff --git a/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp b/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
index a88f8f19f852..c35df47fc051 100644
--- a/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
+++ b/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
@@ -641,6 +641,13 @@ Value *ConstantOffsetExtractor::applyExts(Value *V) {
     }

     Instruction *Ext = I->clone();
+    if (TruncInst *TI = dyn_cast<TruncInst>(Ext)) {
+      // When moving a truncation earlier (e.g., from trunc(add x, c) to
+      // add(trunc x, trunc c)), we cannot preserve NSW/NUW flags because
+      // the truncation of x might be poison even if truncation of (x+c) is not.
+      TI->setHasNoSignedWrap(false);
+      TI->setHasNoUnsignedWrap(false);
+    }
     Ext->setOperand(0, Current);
     Ext->insertBefore(*IP->getParent(), IP);
     Current = Ext;

